Quick reference for Drizzle's query builder and relational query API.

```typescript
import { eq, ne, gt, gte, lt, lte, like, ilike, inArray, and, or, desc, asc, sql, count, avg, max } from 'drizzle-orm';

// INSERT
const [user] = await db.insert(users).values({ name: 'Alice', email: 'a@test.com' }).returning();

// Bulk insert
await db.insert(users).values([
  { name: 'Bob', email: 'b@test.com' },
  { name: 'Charlie', email: 'c@test.com' },
]);

// SELECT with filters
const activeAdmins = await db.select()
  .from(users)
  .where(and(eq(users.role, 'admin'), eq(users.isActive, true)))
  .orderBy(desc(users.createdAt))
  .limit(20)
  .offset(0);

// Relational query (like Prisma includes)
const usersWithPosts = await db.query.users.findMany({
  where: eq(users.isActive, true),
  with: { posts: { where: eq(posts.status, 'published'), limit: 5 } },
});

// UPDATE
await db.update(users)
  .set({ name: 'Alice Updated', updatedAt: sql`now()` })
  .where(eq(users.id, 1));

// DELETE
await db.delete(users).where(eq(users.id, 1));

// AGGREGATE
const [stats] = await db.select({
  total: count(),
  avgViews: avg(posts.viewCount),
  maxViews: max(posts.viewCount),
}).from(posts).where(eq(posts.status, 'published'));

// UPSERT
await db.insert(users)
  .values({ id: 1, name: 'Alice', email: 'a@test.com' })
  .onConflictDoUpdate({ target: users.email, set: { name: 'Alice' } });
```

