Log slow queries with timing information using Prisma's event system.

```typescript
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient({
  log: [
    { emit: 'event', level: 'query' },
    { emit: 'stdout', level: 'warn' },
    { emit: 'stdout', level: 'error' },
  ],
});

// Log all queries with timing
prisma.$on('query', (e) => {
  if (e.duration > 100) { // Only log slow queries (>100ms)
    console.warn(`Slow query (${e.duration}ms):`, {
      query: e.query,
      params: e.params,
      duration: e.duration,
    });
  }
});

// Or use client extension for per-operation timing
const prismaWithTiming = prisma.$extends({
  query: {
    $allModels: {
      async $allOperations({ operation, model, args, query }) {
        const start = performance.now();
        const result = await query(args);
        const duration = performance.now() - start;
        if (duration > 100) {
          console.warn(`[${model}.${operation}] ${duration.toFixed(1)}ms`);
        }
        return result;
      },
    },
  },
});
```

In production, send slow query logs to your observability platform (Datadog, Grafana, etc.) instead of console.warn.

Reusable SQL helpers for common patterns like array operations, JSON queries, and date math.

```typescript
import { sql, SQL } from 'drizzle-orm';
import { AnyPgColumn } from 'drizzle-orm/pg-core';

// Array contains
export function arrayContains(column: AnyPgColumn, value: string) {
  return sql`${value} = ANY(${column})`;
}

// JSON field access
export function jsonField(column: AnyPgColumn, path: string) {
  return sql`${column}->>${path}`;
}

// Date within last N days
export function withinDays(column: AnyPgColumn, days: number) {
  return sql`${column} > NOW() - INTERVAL '${sql.raw(String(days))} days'`;
}

// Case-insensitive search across multiple columns
export function searchAcross(term: string, ...columns: AnyPgColumn[]): SQL {
  const conditions = columns.map(
    (col) => sql`${col} ILIKE ${'%' + term + '%'}`
  );
  return sql.join(conditions, sql` OR `);
}

// Usage
const results = await db.select().from(posts)
  .where(and(
    withinDays(posts.createdAt, 30),
    searchAcross('typescript', posts.title, posts.content),
  ));

const taggedPosts = await db.select().from(posts)
  .where(arrayContains(posts.tags, 'drizzle'));
```

These helpers compose with Drizzle's `and()`, `or()`, and `where()` just like built-in operators.

Use Prisma in Next.js Server Actions with proper error handling and revalidation.

```typescript
// app/actions/user.ts
'use server';

import { prisma } from '@/lib/prisma';
import { revalidatePath } from 'next/cache';
import { z } from 'zod';

const updateProfileSchema = z.object({
  name: z.string().min(1).max(100),
  bio: z.string().max(500).optional(),
});

export async function updateProfile(formData: FormData) {
  const parsed = updateProfileSchema.safeParse({
    name: formData.get('name'),
    bio: formData.get('bio'),
  });

  if (!parsed.success) {
    return { error: parsed.error.flatten().fieldErrors };
  }

  try {
    await prisma.user.update({
      where: { id: getCurrentUserId() },
      data: parsed.data,
    });
    revalidatePath('/profile');
    return { success: true };
  } catch (e) {
    if (e instanceof Prisma.PrismaClientKnownRequestError) {
      if (e.code === 'P2025') return { error: { _form: ['User not found'] } };
    }
    return { error: { _form: ['Something went wrong'] } };
  }
}

// app/profile/page.tsx
export default async function ProfilePage() {
  const user = await prisma.user.findUniqueOrThrow({
    where: { id: getCurrentUserId() },
  });

  return (
    <form action={updateProfile}>
      <input name="name" defaultValue={user.name} />
      <textarea name="bio" defaultValue={user.bio ?? ''} />
      <button type="submit">Save</button>
    </form>
  );
}
```

Use Postgres savepoints within Drizzle transactions for partial rollback.

```typescript
import { sql } from 'drizzle-orm';

await db.transaction(async (tx) => {
  // Step 1: always runs
  await tx.insert(orders).values({
    userId: 1,
    total: 99.99,
    status: 'pending',
  });

  // Step 2: optional, can fail without rolling back step 1
  try {
    await tx.execute(sql`SAVEPOINT send_notification`);
    await tx.insert(notifications).values({
      userId: 1,
      message: 'Order placed!',
    });
    await tx.execute(sql`RELEASE SAVEPOINT send_notification`);
  } catch (e) {
    // Rollback only the notification, keep the order
    await tx.execute(sql`ROLLBACK TO SAVEPOINT send_notification`);
    console.warn('Notification failed, order still created:', e);
  }

  // Step 3: update inventory (must succeed)
  await tx.update(products)
    .set({ stock: sql`stock - 1` })
    .where(eq(products.id, productId));
});
```

Savepoints let you create nested "sub-transactions" within a larger transaction. If a savepoint fails, you can rollback to it without affecting work done before the savepoint.

Run each test in a transaction that rolls back, keeping the database clean without migrations or truncation.

```typescript
// test/helpers/prisma.ts
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export async function withTestTransaction<T>(
  fn: (tx: Parameters<Parameters<typeof prisma.$transaction>[0]>[0]) => Promise<T>
): Promise<T> {
  try {
    return await prisma.$transaction(async (tx) => {
      const result = await fn(tx);
      // Force rollback by throwing after test completes
      throw { __rollback: true, result };
    });
  } catch (e: any) {
    if (e.__rollback) return e.result;
    throw e;
  }
}

// Usage in tests
import { describe, it, expect } from 'vitest';
import { withTestTransaction } from './helpers/prisma';

describe('UserService', () => {
  it('creates a user', async () => {
    await withTestTransaction(async (tx) => {
      const user = await tx.user.create({
        data: { email: 'test@test.com', name: 'Test' },
      });
      expect(user.email).toBe('test@test.com');

      const found = await tx.user.findUnique({ where: { id: user.id } });
      expect(found).not.toBeNull();
    });
    // Transaction rolled back — no cleanup needed
  });
});
```

Use Drizzle subqueries for complex aggregations that can't be expressed with simple joins.

```typescript
import { db } from './db';
import { users, posts, comments } from './schema';
import { eq, sql, desc, count } from 'drizzle-orm';

// Subquery: users with their post count and latest post date
const postStats = db
  .select({
    authorId: posts.authorId,
    postCount: count().as('post_count'),
    latestPost: sql<Date>`MAX(${posts.createdAt})`.as('latest_post'),
  })
  .from(posts)
  .groupBy(posts.authorId)
  .as('post_stats');

const usersWithStats = await db
  .select({
    id: users.id,
    name: users.name,
    email: users.email,
    postCount: postStats.postCount,
    latestPost: postStats.latestPost,
  })
  .from(users)
  .leftJoin(postStats, eq(users.id, postStats.authorId))
  .orderBy(desc(postStats.postCount));

// Correlated subquery: users who posted in the last 7 days
const recentPosters = await db
  .select()
  .from(users)
  .where(
    sql`EXISTS (
      SELECT 1 FROM ${posts}
      WHERE ${posts.authorId} = ${users.id}
      AND ${posts.createdAt} > NOW() - INTERVAL '7 days'
    )`
  );
```

The `.as('alias')` call is required for subquery columns. Without it, Drizzle can't reference the column in the outer query.

Efficient bulk insert, update, and delete patterns with Drizzle.

```typescript
import { eq, inArray, sql } from 'drizzle-orm';

// Bulk insert with returning
const newUsers = await db.insert(users)
  .values([
    { name: 'Alice', email: 'a@test.com' },
    { name: 'Bob', email: 'b@test.com' },
    { name: 'Charlie', email: 'c@test.com' },
  ])
  .returning({ id: users.id, email: users.email });
// [{ id: 1, email: 'a@test.com' }, ...]

// Bulk upsert
const userData = [{ email: 'a@test.com', name: 'Alice V2' }];
await db.insert(users)
  .values(userData)
  .onConflictDoUpdate({
    target: users.email,
    set: { name: sql`excluded.name`, updatedAt: sql`now()` },
  });

// Bulk update with different values per row (using CASE)
const updates = [{ id: 1, name: 'New Alice' }, { id: 2, name: 'New Bob' }];
await db.execute(sql`
  UPDATE users SET name = CASE id
    ${sql.join(updates.map(u => sql`WHEN ${u.id} THEN ${u.name}`), sql` `)}
  END
  WHERE id IN (${sql.join(updates.map(u => sql`${u.id}`), sql`, `)})
`);

// Bulk delete with returning
const deleted = await db.delete(users)
  .where(inArray(users.id, [1, 2, 3]))
  .returning();
```

The `sql.join()` helper is essential for dynamic SQL in bulk operations. Always use `returning()` to get back the affected rows without a separate query.

Complete drizzle.config.ts with all available options and their effects.

```typescript
import { defineConfig } from 'drizzle-kit';

export default defineConfig({
  // Path to your schema file(s)
  schema: './src/db/schema/index.ts',
  // Or multiple files:
  // schema: ['./src/db/schema/users.ts', './src/db/schema/posts.ts'],

  // Output directory for migration files
  out: './drizzle/migrations',

  // Database dialect
  dialect: 'postgresql', // 'postgresql' | 'mysql' | 'sqlite'

  // Database connection
  dbCredentials: {
    url: process.env.DATABASE_URL!,
    // Or individual fields:
    // host: 'localhost',
    // port: 5432,
    // user: 'postgres',
    // password: 'secret',
    // database: 'mydb',
    // ssl: true,
  },

  // Print SQL statements during generate/push
  verbose: true,

  // Ask for confirmation before destructive changes
  strict: true,

  // Table name filters (regex patterns)
  tablesFilter: ['!_prisma_migrations'], // exclude Prisma migration table

  // Schema filters (Postgres only)
  schemaFilter: ['public', 'app'],
});
```

The `tablesFilter` option is useful when migrating from Prisma to Drizzle — exclude Prisma's internal tables. Use `schemaFilter` for multi-schema Postgres setups.

Key differences in performance characteristics between Prisma and Drizzle.

**Bundle size:**
- Prisma: ~2MB+ (query engine binary + generated client)
- Drizzle: ~50KB (pure JavaScript, no engine binary)

**Query overhead:**
- Prisma: queries go through the Rust query engine (IPC overhead)
- Drizzle: generates SQL directly in JavaScript, sends to driver

**Cold start (serverless):**
- Prisma: 500ms-2s (loading query engine)
- Drizzle: 50-100ms (pure JS module load)

```typescript
// Prisma — generated SQL has extra wrapping
await prisma.user.findMany({ where: { role: 'admin' } });
// SELECT "public"."User"."id", "public"."User"."name", ... FROM "public"."User" WHERE "public"."User"."role" = $1

// Drizzle — SQL matches what you write
await db.select().from(users).where(eq(users.role, 'admin'));
// SELECT "id", "name", ... FROM "users" WHERE "role" = $1
```

**When to choose Prisma:** rapid prototyping, complex relations, existing Prisma codebase, auto-generated migrations.

**When to choose Drizzle:** serverless/edge, bundle size matters, SQL-native developers, performance-critical apps.
